const paper = $input.item.json;
const apiKey = $env.OPENAI_API_KEY;

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o-mini',
    max_tokens: 1500,
    messages: [
      { role: 'system', content: 'You are a careful academic reader. When given a paper, produce a structured summary with these clearly labelled sections:\n\n## Problem & Motivation\n## Proposed Method\n## Methods\n## Results\n## Claimed Contributions\n\nBe factual and concise. Include specific numbers from experiments.' },
      { role: 'user', content: 'Please summarise the following paper:\n\nTitle: ' + paper.title + '\n\n' + paper.paper_text }
    ]
  },
  json: true
});

const summary = data.choices[0].message.content;

return [{ json: { paper_id: paper.paper_id, title: paper.title, paper_text: paper.paper_text, reader_summary: summary } }];

const ctx = $input.item.json;
const apiKey = $env.OPENAI_API_KEY;

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o',
    max_tokens: 1200,
    messages: [
      { role: 'system', content: 'You are a rigorous peer reviewer for a top-tier ML/AI venue. Given a paper and its summary, identify substantive weaknesses in: novelty, methodology, evaluation, clarity, and reproducibility. For each point give: (a) the issue, (b) why it matters, (c) what specific evidence from the paper supports your concern. Be specific and cite details from the paper.' },
      { role: 'user', content: 'Paper title: ' + ctx.title + '\n\nPaper text:\n' + ctx.paper_text + '\n\nReader summary:\n' + ctx.reader_summary + '\n\nNow list your critique points.' }
    ]
  },
  json: true
});

const critique = data.choices[0].message.content;

return [{ json: { ...ctx, critic_points: critique } }];

const ctx = $input.item.json;
const apiKey = $env.OPENAI_API_KEY;

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o-mini',
    max_tokens: 1000,
    messages: [
      { role: 'system', content: 'You are a senior programme committee member auditing a peer review. Your job is to challenge poorly-supported critique points: ask for concrete evidence, flag over-interpretations, and identify any points that are actually addressed in the paper. Also highlight genuine issues the Critic may have missed. Be constructive but demanding.' },
      { role: 'user', content: 'Paper summary:\n' + ctx.reader_summary + '\n\nCritic points:\n' + ctx.critic_points + '\n\nChallenge weak points and identify anything important that was missed.' }
    ]
  },
  json: true
});

const auditFeedback = data.choices[0].message.content;

return [{ json: { ...ctx, auditor_feedback: auditFeedback } }];

const ctx = $input.item.json;
const apiKey = $env.OPENAI_API_KEY;

const schema = '{"summary":"<2-3 sentence summary>","strengths":[{"point":"<strength>","evidence":"<evidence>"}],"weaknesses":[{"point":"<weakness>","evidence":"<evidence>"}],"questions":[{"question":"<question>","motivation":"<why it matters>"}],"scores":{"correctness":"<1-5>","novelty":"<1-5>","recommendation":"<accept|borderline|reject>","confidence":"<1-5>"}}';

const transcript = '=== Reader ===\n' + ctx.reader_summary + '\n\n=== Critic ===\n' + ctx.critic_points + '\n\n=== Auditor ===\n' + ctx.auditor_feedback;

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o',
    max_tokens: 800,
    messages: [
      { role: 'system', content: 'You are a senior editor writing a peer review of the PAPER described in the transcript. The strengths and weaknesses must be about the PAPER ITSELF (its novelty, methodology, evaluation, clarity, reproducibility) — NOT about the quality of the critique or debate. Extract the best-supported paper-level points raised across the debate. Output ONLY valid JSON matching this schema: ' + schema + ' Rules: 3-8 strengths, 3-8 weaknesses, 2-5 questions. No markdown fences, no commentary.' },
      { role: 'user', content: 'Full debate transcript:\n\n' + transcript + '\n\nProduce the final structured review JSON.' }
    ]
  },
  json: true
});

let raw = data.choices[0].message.content.trim();
if (raw.startsWith('```')) {
  raw = raw.split('```')[1];
  if (raw.startsWith('json')) raw = raw.slice(4);
}

let structured;
try { structured = JSON.parse(raw); } catch(e) { structured = { raw: raw }; }

return [{ json: { paper_id: ctx.paper_id, output: structured } }];
